doc = Rhino.RhinoDoc.ActiveDoc
counts = {}
for obj in doc.Objects:
    idx = obj.Attributes.LayerIndex
    counts[idx] = counts.get(idx, 0) + 1
rows = []
for layer in doc.Layers:
    rows.append({"index": layer.Index, "name": layer.FullPath, "visible": layer.IsVisible, "count": counts.get(layer.Index, 0)})
return {"layer_count": doc.Layers.Count, "layers": rows}
